import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

export default function Profile() {
    const { username } = useParams();
    const [user, setUser] = useState(null);

    useEffect(() => {
        fetchUser();
    }, [username]);

    const fetchUser = async () => {
        try {
            const response = await axios.get(`/users/`);
            const found = response.data.results?.find(u => u.username === username);
            setUser(found);
        } catch (error) {
            console.error('Error fetching user:', error);
        }
    };

    if (!user) return <div className="text-white text-center">Загрузка...</div>;

    return (
        <div className="container mx-auto px-4 py-8">
            <div className="bg-gray-900 rounded-lg p-8">
                <h1 className="text-3xl font-bold text-white">{user.username}</h1>
                <p className="text-gray-400 mt-2">Подписчиков: {user.subscriber_count}</p>
                <p className="text-gray-400">Видео: {user.video_count}</p>
            </div>
        </div>
    );
}
